var doc = Rhino.RhinoDoc.ActiveDoc;
var rows = new List<object>();
foreach (var view in doc.Views)
{
    var vp = view.ActiveViewport;
    rows.Add(new {
        name = view.MainViewport.Name,
        projection = vp.IsParallelProjection ? "parallel" : (vp.IsPerspectiveProjection ? "perspective" : "other"),
        camera_location = new { x = vp.CameraLocation.X, y = vp.CameraLocation.Y, z = vp.CameraLocation.Z },
        target = new { x = vp.CameraTarget.X, y = vp.CameraTarget.Y, z = vp.CameraTarget.Z }
    });
}
return new { count = rows.Count, viewports = rows };
